import { generateId } from './ids';
import { WALL_THICKNESS, DOOR_WIDTH, WINDOW_WIDTH, ROOM_COLOR } from './defaults';

export function createProject(name = 'Untitled Project') {
  return {
    id: generateId('proj'),
    name,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    floors: [createFloor('Ground Floor', 0)],
    version: 1,
  };
}

export function createFloor(name = 'Floor', level = 0) {
  return {
    id: generateId('floor'),
    name,
    level,
    walls: [],
    rooms: [],
    doors: [],
    windows: [],
  };
}

export function createWall(start, end, thickness = WALL_THICKNESS) {
  return {
    id: generateId('wall'),
    start: { x: start.x, y: start.y },
    end: { x: end.x, y: end.y },
    thickness,
  };
}

export function createDoor(wallId, offset, width = DOOR_WIDTH, openDirection = 'left') {
  return {
    id: generateId('door'),
    wallId,
    offset,
    width,
    openDirection,
  };
}

export function createWindow(wallId, offset, width = WINDOW_WIDTH) {
  return {
    id: generateId('win'),
    wallId,
    offset,
    width,
  };
}

export function createRoom(name = 'Room', labelPosition = { x: 0, y: 0 }, color = ROOM_COLOR) {
  return {
    id: generateId('room'),
    name,
    labelPosition: { ...labelPosition },
    color,
  };
}

