              <path
                d={`M ${door.width} 0 A ${door.width} ${door.width} 0 0 ${door.openDirection === 'left' ? 1 : 0} 0 ${flipSign * -door.width}`}
                fill="none"
                stroke="var(--color-wall-fill)"
                strokeWidth={1}
                strokeDasharray="4 3"
                vectorEffect="non-scaling-stroke"
              />
            </g>
          </g>
        );
      })}
    </g>
  );
}

