  1→import { useState, useEffect, useCallback } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider } from './EditorProvider';
  4→import SvgCanvas from '@/renderers/SvgCanvas';
  5→import Toolbar from '@/ui/Toolbar';
  6→import Sidebar from '@/ui/Sidebar';
  7→import PropertiesPanel from '@/ui/PropertiesPanel';
  8→import Modal from '@/ui/Modal';
  9→import { createProject } from '@/domain/models';
 10→import { saveProject, loadProject, listProjects } from '@/persistence/storage';
 11→import styles from './App.module.css';
 12→
 13→function AppInner() {
 14→  const { project, isDirty, dispatch } = useProject();
 15→  const [showLoadModal, setShowLoadModal] = useState(false);
 16→  const [savedProjects, setSavedProjects] = useState([]);
 17→
 18→  // beforeunload warning
 19→  useEffect(() => {
 20→    const handler = (e) => {
 21→      if (isDirty) {
 22→        e.preventDefault();
 23→        e.returnValue = '';
 24→      }
 25→    };
 26→    window.addEventListener('beforeunload', handler);
 27→    return () => window.removeEventListener('beforeunload', handler);
 28→  }, [isDirty]);
 29→
 30→  // Ctrl+S save
 31→  useEffect(() => {
 32→    const handler = (e) => {
 33→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
 34→        e.preventDefault();
 35→        handleSave();
 36→      }
 37→    };
 38→    window.addEventListener('keydown', handler);
 39→    return () => window.removeEventListener('keydown', handler);
 40→  }, [project]);
 41→
 42→  const handleNew = useCallback(() => {
 43→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 44→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
 45→  }, [isDirty, dispatch]);
 46→
 47→  const handleSave = useCallback(() => {
 48→    saveProject(project);
 49→    dispatch({ type: 'MARK_SAVED' });
 50→  }, [project, dispatch]);
 51→
 52→  const handleLoadClick = useCallback(() => {
 53→    setSavedProjects(listProjects());
 54→    setShowLoadModal(true);
 55→  }, []);
 56→
 57→  const handleLoad = useCallback((id) => {
 58→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 59→    try {
 60→      const { project: loaded, savedAt } = loadProject(id);
 61→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
 62→      setShowLoadModal(false);
 63→    } catch (err) {
 64→      alert('Failed to load project: ' + err.message);
 65→    }
 66→  }, [isDirty, dispatch]);
 67→
 68→  const activeFloorId = project.floors[0]?.id;
 69→
 70→  return (
 71→    <EditorProvider activeFloorId={activeFloorId}>
 72→      <div className={styles.layout}>
 73→        <div className={styles.toolbar}>
 74→          <Toolbar onNew={handleNew} onSave={handleSave} onLoad={handleLoadClick} />
 75→        </div>
 76→        <div className={styles.sidebar}>
 77→          <Sidebar />
 78→        </div>
 79→        <div className={styles.canvas}>
 80→          <SvgCanvas />
 81→        </div>
 82→        <div className={styles.properties}>
 83→          <PropertiesPanel />
 84→        </div>
 85→      </div>
 86→
 87→      {showLoadModal && (
 88→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
 89→          {savedProjects.length === 0 ? (
 90→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
 91→              No saved projects found.
 92→            </p>
 93→          ) : (
 94→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
 95→              {savedProjects.map(p => (
 96→                <button
 97→                  key={p.id}
 98→                  onClick={() => handleLoad(p.id)}
 99→                  style={{
100→                    display: 'flex',
101→                    justifyContent: 'space-between',
102→                    padding: '10px 12px',
103→                    border: '1px solid var(--color-border)',
104→                    borderRadius: 'var(--radius-sm)',
105→                    cursor: 'pointer',
106→                    background: 'white',
107→                    fontSize: '13px',
108→                  }}
109→                >
110→                  <span style={{ fontWeight: 500 }}>{p.name}</span>
