  1→import { createWall } from '@/domain/models';
  2→import { distance } from '@/geometry/point';
  3→import { SNAP_DISTANCE_PX, MIN_WALL_LENGTH } from '@/domain/defaults';
  4→
  5→function snapToEndpoints(modelPos, walls, snapDistModel, chainStart) {
  6→  let best = null;
  7→  let bestDist = snapDistModel;
  8→
  9→  // Snap to chain start to close loop
 10→  if (chainStart) {
 11→    const d = distance(modelPos, chainStart);
 12→    if (d < bestDist) {
 13→      best = chainStart;
 14→      bestDist = d;
 15→    }
 16→  }
 17→
 18→  for (const wall of walls) {
 19→    for (const pt of [wall.start, wall.end]) {
 20→      const d = distance(modelPos, pt);
 21→      if (d < bestDist) {
 22→        best = pt;
 23→        bestDist = d;
 24→      }
 25→    }
 26→  }
 27→  return best;
 28→}
 29→
 30→function constrainAngle(start, end, shiftHeld) {
 31→  if (!shiftHeld) return end;
 32→  const dx = end.x - start.x;
 33→  const dy = end.y - start.y;
 34→  const angle = Math.atan2(dy, dx);
 35→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 36→  const len = Math.sqrt(dx * dx + dy * dy);
 37→  return {
 38→    x: start.x + Math.cos(snapAngle) * len,
 39→    y: start.y + Math.sin(snapAngle) * len,
 40→  };
 41→}
 42→
 43→export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 44→  return {
 45→    onMouseDown(modelPos, e, toolState) {
 46→      if (e.button !== 0) return;
 47→
 48→      const floor = getFloor(activeFloorId);
 49→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 50→      const shiftHeld = e.shiftKey;
 51→
 52→      let snapped = modelPos;
 53→      if (snapEnabled) {
 54→        const snapPt = snapToEndpoints(modelPos, floor.walls, snapDistModel, toolState.chainStart);
 55→        if (snapPt) snapped = { ...snapPt };
 56→      }
 57→      snapped = constrainAngle(toolState.start || snapped, snapped, shiftHeld && toolState.start);
 58→      if (toolState.start && shiftHeld) {
 59→        snapped = constrainAngle(toolState.start, snapped, true);
 60→      }
 61→
 62→      if (!toolState.start) {
 63→        // First click: set start
 64→        editorDispatch({
 65→          type: 'UPDATE_TOOL_STATE',
 66→          payload: { start: snapped, chainStart: snapped, preview: null },
 67→        });
 68→      } else {
 69→        // Second+ click: create wall and chain
 70→        let endPt = snapped;
 71→        if (shiftHeld) {
 72→          endPt = constrainAngle(toolState.start, snapped, true);
 73→        }
 74→
 75→        const len = distance(toolState.start, endPt);
 76→        if (len < MIN_WALL_LENGTH) return;
 77→
 78→        const wall = createWall(toolState.start, endPt);
 79→        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
 80→
 81→        // Check if we snapped back to chain start (close loop)
 82→        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
 83→          editorDispatch({
 84→            type: 'UPDATE_TOOL_STATE',
 85→            payload: { start: null, chainStart: null, preview: null },
 86→          });
 87→        } else {
 88→          // Chain: end becomes new start
 89→          editorDispatch({
 90→            type: 'UPDATE_TOOL_STATE',
 91→            payload: { start: endPt, preview: null },
 92→          });
 93→        }
 94→      }
 95→    },
 96→
 97→    onMouseMove(modelPos, e, toolState) {
 98→      if (!toolState.start) return;
 99→      let preview = modelPos;
100→      if (e.shiftKey) {
101→        preview = constrainAngle(toolState.start, modelPos, true);
102→      }
103→
104→      const floor = getFloor(activeFloorId);
105→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
106→      if (snapEnabled) {
107→        const snapPt = snapToEndpoints(preview, floor.walls, snapDistModel, toolState.chainStart);
108→        if (snapPt) preview = { ...snapPt };
109→      }
110→
111→      editorDispatch({
112→        type: 'UPDATE_TOOL_STATE',
113→        payload: { preview },
114→      });
115→    },
116→
117→    onDoubleClick(modelPos, e, toolState) {
118→      // Finish chain
119→      editorDispatch({
120→        type: 'UPDATE_TOOL_STATE',
121→        payload: { start: null, chainStart: null, preview: null },
122→      });
123→    },
124→
125→    onKeyDown(e, toolState) {
126→      if (e.key === 'Escape') {
127→        editorDispatch({
128→          type: 'UPDATE_TOOL_STATE',
129→          payload: { start: null, chainStart: null, preview: null },
130→        });
131→      }
132→    },
133→
134→    getCursor(toolState) {
135→      return 'crosshair';
136→    },
137→  };
138→}
