22→export function pointInPolygon(point, polygon) {
23→  let inside = false;
24→  const n = polygon.length;
25→  for (let i = 0, j = n - 1; i < n; j = i++) {
26→    const xi = polygon[i].x, yi = polygon[i].y;
27→    const xj = polygon[j].x, yj = polygon[j].y;
28→    if (
29→      yi > point.y !== yj > point.y &&
30→      point.x < ((xj - xi) * (point.y - yi)) / (yj - yi) + xi
31→    ) {
32→      inside = !inside;
33→    }
34→  }
