 4→export default function WallPreview({ toolState, activeTool }) {
 5→  if (activeTool !== TOOLS.WALL || !toolState.start || !toolState.preview) {
 6→    return null;
 7→  }
 8→
 9→  const { start, preview } = toolState;
10→  const len = distance(start, preview);
11→  const label = (len / 1000).toFixed(2) + ' m';
12→  const midX = (start.x + preview.x) / 2;
13→  const midY = (start.y + preview.y) / 2;
14→
15→  return (
16→    <g className="wall-preview" style={{ pointerEvents: 'none' }}>
17→      <line
18→        x1={start.x} y1={start.y}
19→        x2={preview.x} y2={preview.y}
20→        stroke="var(--color-selection)"
21→        strokeWidth={2}
22→        strokeDasharray="8 4"
23→        vectorEffect="non-scaling-stroke"
24→        opacity={0.7}
25→      />
26→      <circle
27→        cx={start.x} cy={start.y} r={4}
28→        fill="var(--color-selection)"
29→        vectorEffect="non-scaling-stroke"
30→      />
31→      <circle
32→        cx={preview.x} cy={preview.y} r={4}
33→        fill="var(--color-selection)"
34→        vectorEffect="non-scaling-stroke"
35→      />
36→      <text
37→        x={midX} y={midY}
38→        textAnchor="middle"
39→        dy={-150}
40→        fill="var(--color-selection)"
41→        fontSize={140}
42→        fontFamily="var(--font-blueprint)"
43→      >
44→        {label}
45→      </text>
46→    </g>
47→  );
48→}
