 4→const DIMENSION_OFFSET = 300; // mm from wall centerline
 5→
 6→export function computeWallDimension(wall) {
 7→  const len = wallLength(wall);
 8→  const dir = wallDirection(wall);
 9→  const perp = perpendicular(dir);
10→  const offset = scale(perp, -(wall.thickness / 2 + DIMENSION_OFFSET));
11→
12→  const start = add(wall.start, offset);
13→  const end = add(wall.end, offset);
14→  const mid = midpoint(start, end);
15→  const extStart = add(wall.start, scale(perp, -(wall.thickness / 2 + 50)));
16→  const extEnd = add(wall.end, scale(perp, -(wall.thickness / 2 + 50)));
17→
18→  const meters = len / 1000;
19→  const label = meters.toFixed(2) + ' m';
20→
21→  const angleDeg = Math.atan2(dir.y, dir.x) * (180 / Math.PI);
22→  // Flip text if upside down
23→  const textAngle = (angleDeg > 90 || angleDeg < -90)
24→    ? angleDeg + 180
25→    : angleDeg;
26→
27→  return {
28→    start,
29→    end,
30→    mid,
31→    extStart,
32→    extEnd,
33→    extStartOuter: add(wall.start, offset),
34→    extEndOuter: add(wall.end, offset),
35→    label,
36→    angle: textAngle,
37→    length: len,
38→  };
